pub fn handle_request(req: Request) -> Response {
    let data = parse(req.body)?;
    Ok(data)
}

pub fn parse(input: &str) -> Option<Data> {
    let parts: Vec<&str> = input.split(',').collect();
    let name = parts.get(0).unwrap().to_string();
    let value = parts.get(1).unwrap().to_string();
    Some(Data { name, value })
}
